<style>
  /* Global font stack */
  :global(html, body) {
    margin: 0;
    height: 100%;
    font-family: 'Roboto Mono', -apple-system, BlinkMacSystemFont,
                 "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  }

  .app-container {
    display: flex;
    height: 100vh;
    background: #0d0d0d;
    color: #e0e0e0;
    overflow: hidden;
  }

  .sidebar {
    width: 240px;
    background: #191919;
    display: flex;
    flex-direction: column;
    /* push main menu down to align with content’s search bar */
    padding-top: calc(1.5rem + 3rem);
    padding: 0.75rem;
  }

.nav-list {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  padding-top: 5.7rem; /* ← pushes tabs down */
}


  .nav-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    background: transparent;
    border: none;
    color: inherit;
    font-size: 1.05rem;
    font-weight: 600;
    padding: 0.75rem;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.2s;
  }
  .nav-item:hover {
    background: #3a3a3a;
  }
  .nav-item.active {
    background: #4a4a4a;
  }

  .settings {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    background: transparent;
    border: none;
    color: inherit;
    font-size: 1.05rem;
    font-weight: 600;
    padding: 0.75rem;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.2s;
    margin-top: auto; /* push to bottom */
  }
  .settings:hover {
    background: #3a3a3a;
  }

  .icon {
    width: 1.25rem;
    height: 1.25rem;
    flex-shrink: 0;
  }

  .content {
    flex: 1;
    padding: 1.5rem;
    background: #0d0d0d;
    overflow-y: auto;
  }
</style>
